import React, { useState } from 'react'
import { Container, Grid, Paper, Tab, Tabs } from '@material-ui/core'
import StudentActivities from '../components/StudentActivities'


export default function StudentFeed() {

  const [selectedTab, setSelectedTab] = React.useState(0);

  const handleChange = (event, newValue) => {
    setSelectedTab(newValue);
  };

  const [activities, setActivities] = useState([
    { title: 'Assignment 1mahaba mabahabaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa', body: 'May 11', id: 1 },
    { title: 'Assignment 2mahaba mabahabaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa', body: 'May 2', id: 2 },
    { title: 'Assignment 3mahaba mabahabaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa', body: 'May 3', id: 3 },
    { title: 'Assignment 4mahaba mabahabaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa', body: 'May 4', id: 4 },
    { title: 'Assignment 5mahaba mabahabaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa', body: 'May 5', id: 5 },
    { title: 'Assignment 6mahaba mabahabaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa', body: 'May 6', id: 6 },
    { title: 'Assignment 7mahaba mabahabaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa', body: 'May 7', id: 7 },
    { title: 'Assignment 8mahaba mabahabaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa', body: 'May 8', id: 8 },
    { title: 'Assignment 9mahaba mabahabaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa', body: 'May 9', id: 9 },
    { title: 'Assignment 10mahaba mabahabaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa', body: 'May 10', id: 10 },
  ])

  return (
    <div>
      <Container>
        <Grid container spacing={3}>
          <Grid item xs={12}>
            <h1>Subject Name here</h1>
            <Paper>
              <Tabs value={selectedTab} onChange={handleChange} centered>
                <Tab label="NewsFeed" />
                <Tab label="Activities" />
              </Tabs>
            </Paper>
            
          </Grid>
          {activities.map(activity => (
            <Grid item xs={12} key={activity.id}>
              {selectedTab === 0 && <StudentActivities activity={activity} />}
            </Grid>
          ))}
        </Grid>
      </Container>
    </div>
  )
}
